function SSLMonitorWidget() {
  const [domains, setDomains] = React.useState([
    { name: 'example.com', days: 45, valid: true },
    { name: 'api.example.com', days: 12, valid: true },
    { name: 'blog.example.com', days: -3, valid: false }
  ]);

  function statusColor(days) {
    if (days < 0) return '#ef4444';
    if (days < 14) return '#f59e0b';
    return '#22c55e';
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>SSL Certificate Monitor</h3>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {domains.map((d) => (
          <div key={d.name} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#1e293b', padding: 10, borderRadius: 8 }}>
            <span style={{ fontSize: 13 }}>{d.name}</span>
            <span style={{ fontSize: 12, fontWeight: 600, color: statusColor(d.days) }}>
              {d.days < 0 ? 'Expired ' + Math.abs(d.days) + 'd ago' : d.days + ' days left'}
            </span>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 12, fontSize: 11, color: '#64748b' }}>Last check: just now</div>
    </div>
  );
}
render(<SSLMonitorWidget/>);
